import base64
# Colle le base64 retourné par Swagger dans la variable ci-dessous
b64_from_swagger = ""
'''
{
  "_id": {
    "$oid": "69c013dd7fba2cf2758dc9f9"
  },
  "image_id": "425f115b-f864-43b5-becb-042cf03025e9",
  "viewer_username": "youssef",
  "owner_username": "youssef",
  "viewed_at": {
    "$date": "2026-03-22T16:07:57.059Z"
  },
  "original_image": "",
  "watermarked_image": ""
}


'''
# Sauvegarde en fichier
watermarked_bytes = base64.b64decode(b64_from_swagger)
with open("image_watermarked.png", "wb") as f:
    f.write(watermarked_bytes)
print("✅ Fichier sauvegardé : image_watermarked.png")